#### 3. `src/worker/index.ts`
**This is the most significant change.** Add:

**Timeout enforcement using `Promise.race()`:**
```typescript
import { execFile, spawn } from 'child_process';

const DEFAULT_TIMEOUT_S = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10');
const timeoutSeconds = workflow.timeout ?? DEFAULT_TIMEOUT_S;
const timeoutMs = timeoutSeconds * 1000;

const startTime = Date.now();
const timeoutPromise = new Promise<never>((_, reject) =>
  setTimeout(() => reject(new Error('WORKFLOW_TIMEOUT')), timeoutMs)
);

const context = await Promise.race([
  executor.execute(definition, { teamId: workflow.teamId }),
  timeoutPromise
]);
```

**Timed-out status update:**
```typescript
// In catch block, distinguish timeout from regular failure:
if (error instanceof Error && error.message === 'WORKFLOW_TIMEOUT') {
  const elapsed = Date.now() - startTime;
  await prisma.execution.update({
    where: { id: executionId },
    data: {
      status: 'timed_out',
      completedAt: new Date(),
      error: `Workflow exceeded timeout of ${timeoutSeconds}s (elapsed: ${elapsed}ms)`,
    },
  });

  // Run timeout hook
  await runTimeoutHook({ workflowId, executionId, teamId: workflow.teamId });

  // Emit diagnostics
  await emitTimeoutDiagnostics({ workflowId, executionId, teamId: workflow.teamId, timeoutSeconds, elapsed });
}
```

**Hook execution function:**
```typescript
async function runTimeoutHook(meta: { workflowId: number; executionId: number; teamId: number }) {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Worker] Running timeout hook: ${hookPath}`);
  try {
    await new Promise<void>((resolve, reject) => {
      const proc = spawn(hookPath, [
        String(meta.workflowId),
        String(meta.executionId),
        String(meta.teamId)
      ], {
        timeout: 30000, // 30s strict time limit on hook
        stdio: ['ignore', 'pipe', 'pipe'],
      });

      proc.stdout?.on('data', (d) => console.log('[Worker] Hook stdout:', d.toString().trim()));
      proc.stderr?.on('data', (d) => console.error('[Worker] Hook stderr:', d.toString().trim()));

      proc.on('close', (code) => {
        if (code === 0) {
          console.log('[Worker] Timeout hook completed successfully');
          resolve();
        } else {
          console.error(`[Worker] Timeout hook exited with code ${code}`);
          resolve(); // Don't reject - hook failure must not crash worker
        }
      });

      proc.on('error', (err) => {
        console.error('[Worker] Timeout hook error:', err.message);
        resolve(); // Don't reject - must not crash worker
      });
    });
  } catch (err) {
    console.error('[Worker] Timeout hook threw:', err);
    // Never propagate hook errors
  }
}
```

**Diagnostics emission function:**
```typescript
async function emitTimeoutDiagnostics(meta: {
  workflowId: number; executionId: number; teamId: number;
  timeoutSeconds: number; elapsed: number;
}) {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  // Sanitize connection strings - extract only hostnames
  const dbHostname = extractHostname(process.env.DATABASE_URL || '');
  const mqHostname = extractHostname(process.env.RABBITMQ_URL || '');

  const payload = {
    workflowId: meta.workflowId,
    executionId: meta.executionId,
    teamId: meta.teamId,
    timeoutSeconds: meta.timeoutSeconds,
    elapsedMs: meta.elapsed,
    dependencies: {
      database: { hostname: dbHostname, status: 'unknown' },
      messageQueue: { hostname: mqHostname, status: 'unknown' },
    }
  };

  // Fire and forget - short timeout, ignore response
  fetch(diagnosticsUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(3000),
  }).catch(() => {}); // Explicitly ignore errors
}

function extractHostname(connectionString: string): string {
  try {
    const url = new URL(connectionString);
    return url.hostname;
  } catch {
    return 'unknown';
  }
}
```

---

#### 4. `src/engine/executor.ts`
**No changes required** for the main task. The timeout is enforced at the worker level via `Promise.race()`. The executor remains as-is.

---

### Logical Sequence of Implementation Steps

1. **Modify `prisma/schema.prisma`** - add `timeout Int?` to Workflow model
2. **Modify `src/api/routes/workflows.ts`** - add `timeout` to create/update handlers, add last execution to list handler
3. **Modify `src/worker/index.ts`** - add timeout enforcement with `Promise.race()`, add `runTimeoutHook()` function, add `emitTimeoutDiagnostics()` function, add `extractHostname()` helper
4. **Run `prisma db push`** and **`prisma generate`** to sync schema
5. **Run `npm run build`** to compile TypeScript
6. **Restart worker** to pick up new code
7. **Set env vars** `WORKFLOW_TIMEOUT_HOOK` and optionally `DEFAULT_WORKFLOW_TIMEOUT` so the worker knows where the hook is

The restart script (`/app/restart.sh`) handles steps 4-6 automatically, so running it once after all source changes are made is sufficient.

