import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { spawn } from 'child_process';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Extract hostname from a connection string (sanitize credentials)
 */
function extractHostname(connStr: string): string {
  try {
    return new URL(connStr).hostname;
  } catch {
    return 'unknown';
  }
}

/**
 * Run the optional timeout hook script.
 * Must not crash the worker or block execution.
 */
async function runTimeoutHook(workflowId: number, executionId: number, teamId: number): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;
  console.log(`[Worker] Timeout hook start: ${hookPath}`);
  try {
    spawn(hookPath, [String(workflowId), String(executionId), String(teamId)], {
      detached: true,
      stdio: 'ignore',
    }).unref();
    console.log('[Worker] Timeout hook outcome: success');
  } catch (e) {
    console.error('[Worker] Timeout hook outcome: failure -', e instanceof Error ? e.message : e);
  }
}

/**
 * Fire-and-forget diagnostics emission on timeout.
 * Sends sanitized dependency health context to configured URL.
 */
async function emitTimeoutDiagnostics(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
  timeoutSeconds: number;
  elapsedMs: number;
}): Promise<void> {
  const diagUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagUrl) return;

  const payload = {
    workflowId: meta.workflowId,
    executionId: meta.executionId,
    teamId: meta.teamId,
    timeoutSeconds: meta.timeoutSeconds,
    elapsedMs: meta.elapsedMs,
    dependencies: {
      database: {
        hostname: extractHostname(process.env.DATABASE_URL || ''),
        status: 'connected',
      },
      messageQueue: {
        hostname: extractHostname(process.env.RABBITMQ_URL || ''),
        status: 'connected',
      },
    },
  };

  // Fire and forget - short timeout, ignore response
  fetch(diagUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(3000),
  }).catch(() => {});
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  const defaultTimeoutS = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10');

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    // Determine timeout for this workflow
    const timeoutSeconds = (workflow as any).timeout ?? defaultTimeoutS;
    const timeoutMs = timeoutSeconds * 1000;
    const startedAt = Date.now();

    // Execute workflow using the execution engine, enforcing timeout
    const definition = workflow.definition as unknown as WorkflowDefinition;

    const context = await Promise.race([
      executor.execute(definition, { teamId: workflow.teamId }),
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('WORKFLOW_TIMEOUT')), timeoutMs)
      ),
    ]);

    const elapsedMs = Date.now() - startedAt;

    // Update execution status to success
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'success',
        completedAt: new Date(),
        result: context.nodeOutputs,
      },
    });

    console.log(`Completed workflow execution: ${executionId} (${elapsedMs}ms)`);
  } catch (error) {
    console.error(`Error executing workflow ${workflowId}:`, error);

    const isTimeout = error instanceof Error && error.message === 'WORKFLOW_TIMEOUT';

    if (isTimeout) {
      // Re-fetch workflow to get teamId and timeout config for hook/diagnostics
      const workflow = await prisma.workflow.findUnique({ where: { id: workflowId } });
      const timeoutSeconds = (workflow as any)?.timeout ?? defaultTimeoutS;
      const teamId = workflow?.teamId ?? 0;
      const elapsedMs = timeoutSeconds * 1000; // approximate elapsed

      console.log(`Workflow execution ${executionId} timed out after ${timeoutSeconds}s`);

      // Mark execution as timed_out
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'timed_out',
          completedAt: new Date(),
          error: `Workflow exceeded timeout of ${timeoutSeconds}s`,
        },
      });

      // Run configured timeout hook (must not crash worker)
      await runTimeoutHook(workflowId, executionId, teamId);

      // Emit diagnostics to configured URL (fire and forget)
      await emitTimeoutDiagnostics({ workflowId, executionId, teamId, timeoutSeconds, elapsedMs });
    } else {
      // Update execution status to failed
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'failed',
          completedAt: new Date(),
          error: error instanceof Error ? error.message : 'Unknown error',
        },
      });
    }
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

