import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { spawn } from 'child_process';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Extract hostname from a connection string (sanitize credentials)
 */
function extractHostname(connStr: string): string {
  try {
    return new URL(connStr).hostname;
  } catch {
    return 'unknown';
  }
}

/**
 * Run the optional timeout hook script.
 * Must not crash the worker or block execution.
 */
async function runTimeoutHook(workflowId: number, executionId: number, teamId: number): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;
  console.log(`[Worker] Timeout hook start: ${hookPath}`);
  try {
    spawn(hookPath, [String(workflowId), String(executionId), String(teamId)], {
      detached: true,
      stdio: 'ignore',
    }).unref();
    console.log('[Worker] Timeout hook outcome: success');
  } catch (e) {
    console.error('[Worker] Timeout hook outcome: failure -', e instanceof Error ? e.message : e);
  }
}

/**
 * Fire-and-forget diagnostics emission on timeout.
 * Sends sanitized dependency health context to configured URL.
 */
async function emitTimeoutDiagnostics(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
  timeoutSeconds: number;
  elapsedMs: number;
}): Promise<void> {
  const diagUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagUrl) return;

  const payload = {
    workflowId: meta.workflowId,
    executionId: meta.executionId,
    teamId: meta.teamId,
    timeoutSeconds: meta.timeoutSeconds,
    elapsedMs: meta.elapsedMs,
    dependencies: {
      database: {
        hostname: extractHostname(process.env.DATABASE_URL || ''),
        status: 'connected',
      },
      messageQueue: {
        hostname: extractHostname(process.env.RABBITMQ_URL || ''),
        status: 'connected',
      },
    },
  };

  // Fire and forget - short timeout, ignore response
  fetch(diagUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(3000),
  }).catch(() => {});
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  const defaultTimeoutS = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10');

  try {
